// TestNewPolicyQuotaController tests the controller initialization.
func TestNewPolicyQuotaController(t *testing.T) {
	logger := logrus.New()
	mockResource := &MockResource{
		eventsChan: make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy]),
	}

	controller := NewPolicyQuotaController(logger, mockResource, 10)

	if controller == nil {
		t.Fatal("Expected controller to be created, got nil")
	}
	if controller.maxPerNamespace != 10 {
		t.Errorf("Expected maxPerNamespace to be 10, got %d", controller.maxPerNamespace)
	}
	if len(controller.namespacePolicyCounts) != 0 {
		t.Errorf("Expected empty namespace policy counts, got %d entries", len(controller.namespacePolicyCounts))
	}
}

// TestCheckQuota tests the quota checking functionality.
func TestCheckQuota(t *testing.T) {
	tests := []struct {
		name            string
		maxPerNamespace int
		currentCount    int
		expectError     bool
	}{
		{
			name:            "under_quota",
			maxPerNamespace: 10,
			currentCount:    5,
			expectError:     false,
		},
		{
			name:            "at_quota",
			maxPerNamespace: 10,
			currentCount:    10,
			expectError:     true,
		},
		{
			name:            "over_quota",
			maxPerNamespace: 10,
			currentCount:    15,
			expectError:     true,
		},
		{
			name:            "unlimited_quota",
			maxPerNamespace: 0,
			currentCount:    100,
			expectError:     false,
		},
		{
			name:            "empty_namespace",
			maxPerNamespace: 10,
			currentCount:    0,
			expectError:     false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			logger := logrus.New()
			mockResource := &MockResource{
				eventsChan: make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy]),
			}

			controller := NewPolicyQuotaController(logger, mockResource, tt.maxPerNamespace)
			controller.namespacePolicyCounts["test-namespace"] = tt.currentCount

			err := controller.CheckQuota("test-namespace")

			if (err != nil) != tt.expectError {
				t.Errorf("Expected error: %v, got error: %v", tt.expectError, err)
			}
		})
	}
}

// TestGetNamespacePolicyCount tests retrieving the policy count for a namespace.
func TestGetNamespacePolicyCount(t *testing.T) {
	logger := logrus.New()
	mockResource := &MockResource{
		eventsChan: make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy]),
	}

	controller := NewPolicyQuotaController(logger, mockResource, 10)

	// Test non-existent namespace
	if count := controller.GetNamespacePolicyCount("non-existent"); count != 0 {
		t.Errorf("Expected 0 for non-existent namespace, got %d", count)
	}

	// Set a count and test retrieval
	controller.namespacePolicyCounts["test-ns"] = 5
	if count := controller.GetNamespacePolicyCount("test-ns"); count != 5 {
		t.Errorf("Expected 5 for test-ns, got %d", count)
	}
}

// TestHandleUpsert tests the upsert event handling.
func TestHandleUpsert(t *testing.T) {
	logger := logrus.New()
	mockResource := &MockResource{
		eventsChan: make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy]),
	}

	controller := NewPolicyQuotaController(logger, mockResource, 10)

	cnp := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-policy",
			Namespace: "test-ns",
		},
	}

	// Test handling the first upsert
	controller.handleUpsert(cnp)

	if count := controller.GetNamespacePolicyCount("test-ns"); count != 1 {
		t.Errorf("Expected 1 policy after upsert, got %d", count)
	}

	// Handle another upsert (should not increment since this is the same policy update)
	controller.handleUpsert(cnp)

	if count := controller.GetNamespacePolicyCount("test-ns"); count != 1 {
		t.Errorf("Expected 1 policy after second upsert (same policy), got %d", count)
	}
}

// TestHandleDelete tests the delete event handling.
func TestHandleDelete(t *testing.T) {
	logger := logrus.New()
	mockResource := &MockResource{
		eventsChan: make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy]),
	}

	controller := NewPolicyQuotaController(logger, mockResource, 10)

	cnp := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-policy",
			Namespace: "test-ns",
		},
	}

	// Set initial count
	controller.namespacePolicyCounts["test-ns"] = 2

	// Test delete
	controller.handleDelete(cnp)

	if count := controller.GetNamespacePolicyCount("test-ns"); count != 1 {
		t.Errorf("Expected 1 policy after delete, got %d", count)
	}

	// Delete again
	controller.handleDelete(cnp)

	if count := controller.GetNamespacePolicyCount("test-ns"); count != 0 {
		t.Errorf("Expected 0 policies after second delete, got %d", count)
	}

	// Verify namespace is removed from map when count reaches 0
	if _, exists := controller.namespacePolicyCounts["test-ns"]; exists {
		t.Error("Expected namespace to be removed from map when count reaches 0")
	}
}

// TestRun tests the main controller loop (basic functionality).
func TestRun(t *testing.T) {
	logger := logrus.New()

	// Create a channel for events
	eventsChan := make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy], 10)

	mockResource := &MockResource{
		eventsChan: eventsChan,
	}

	controller := NewPolicyQuotaController(logger, mockResource, 10)

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	// Run controller in a goroutine
	errChan := make(chan error, 1)
	go func() {
		errChan <- controller.Run(ctx)
	}()

	// Send a sync event
	syncEvent := resource.Event[*cilium_v2.CiliumNetworkPolicy]{
		Kind: resource.Sync,
	}
	syncEvent.markDone = func(err error) {}
	eventsChan <- syncEvent

	// Send an upsert event
	cnp := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-policy",
			Namespace: "test-ns",
		},
	}
	upsertEvent := resource.Event[*cilium_v2.CiliumNetworkPolicy]{
		Kind:   resource.Upsert,
		Object: cnp,
	}
	upsertEvent.markDone = func(err error) {}
	eventsChan <- upsertEvent

	// Give the controller time to process
	// (In a real test, we'd use proper synchronization)

	// Cancel context and close the channel
	cancel()
	close(eventsChan)

	// Wait for controller to finish
	err := <-errChan
	if err != nil && err != context.Canceled {
		t.Errorf("Unexpected error from controller: %v", err)
	}

	// Verify the policy was counted
	if count := controller.GetNamespacePolicyCount("test-ns"); count != 1 {
		t.Errorf("Expected 1 policy after run, got %d", count)
	}
}

